# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>
#include <cassert>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

const double TIME_LIMIT = 1.95;

struct Solver {
    int N, M;
    std::vector<std::vector<int>> initial_stacks; // 0-indexed box values

    // Simulation state
    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int,int>> box_pos; // box_val -> (stack_idx, height_idx)
    long long energy;
    std::vector<std::pair<int,int>> ops; // (box_val+1, dest_stack+1 or 0)
    int next_target; // next box to carry out (0-indexed)

    void init(const std::vector<std::vector<int>>& init_stacks) {
        N = 200;
        M = 10;
        initial_stacks = init_stacks;
    }

    void reset_state() {
        stacks = initial_stacks;
        box_pos.assign(N, {0, 0});
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < (int)stacks[i].size(); j++) {
                box_pos[stacks[i][j]] = {i, j};
            }
        }
        energy = 0;
        ops.clear();
        next_target = 0;
    }

    void do_move(int box_val, int dest_stack) {
        int src = box_pos[box_val].first;
        int h = box_pos[box_val].second;
        int num_moved = stacks[src].size() - h;

        int old_dest_h = stacks[dest_stack].size();
        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_pos[bv] = {dest_stack, old_dest_h + (i - h)};
            stacks[dest_stack].push_back(bv);
        }
        stacks[src].resize(h);

        energy += (num_moved + 1);
        ops.push_back({box_val + 1, dest_stack + 1});
    }

    void do_carry_out(int box_val) {
        int src = box_pos[box_val].first;
        stacks[src].pop_back();
        ops.push_back({box_val + 1, 0});
        next_target++;
    }

    // Check if cascades are possible and execute them
    void do_cascades() {
        while (next_target < N) {
            int src = box_pos[next_target].first;
            if (!stacks[src].empty() && stacks[src].back() == next_target) {
                do_carry_out(next_target);
            } else {
                break;
            }
        }
    }

    // Score a destination for moving a sub-block
    // Lower is better
    double score_dest(int dest, int target_k, const std::vector<int>& block, int block_start, int block_len) {
        if (dest == box_pos[block[block_start]].first) return 1e18; // same stack, invalid

        double score = 0.0;
        const auto& dst = stacks[dest];

        // Prefer shorter stacks
        score += dst.size() * 0.5;

        // Big penalty for covering near-future boxes already at top of dest
        if (!dst.empty()) {
            int top_of_dest = dst.back();
            if (top_of_dest >= target_k && top_of_dest < target_k + 30) {
                // Penalty proportional to how soon that box is needed
                score += 50.0 * (30 - (top_of_dest - target_k)) / 30.0;
            }
        }

        // Check if we're covering other near-future boxes in dest
        for (int i = (int)dst.size() - 1; i >= std::max(0, (int)dst.size() - 5); i--) {
            int bv = dst[i];
            if (bv >= target_k && bv < target_k + 20) {
                score += 10.0;
            }
        }

        // Bonus for empty stacks (but not too much - we want to preserve empties)
        if (dst.empty()) {
            score -= 5.0;
        }

        return score;
    }

    // Find best destination for a sub-block
    int best_dest_for_block(int target_k, const std::vector<int>& block, int block_start, int block_len, int src_stack) {
        double best_score = 1e18;
        int best_d = -1;
        for (int d = 0; d < M; d++) {
            if (d == src_stack) continue;
            double s = score_dest(d, target_k, block, block_start, block_len);
            if (s < best_score) {
                best_score = s;
                best_d = d;
            }
        }
        return best_d;
    }

    // Multi-move strategy: process target k
    // Split the block above k into sub-moves intelligently
    void process_target_multi_move(int target_k, int lookahead_window) {
        int src = box_pos[target_k].first;
        int h = box_pos[target_k].second;
        int stack_top = stacks[src].size();

        if (h == stack_top - 1) {
            // Already on top
            do_carry_out(target_k);
            return;
        }

        // Boxes above target: stacks[src][h+1], ..., stacks[src][stack_top-1]
        // We process from top down, deciding how to split
        std::vector<int> above;
        above.reserve(stack_top - h - 1);
        for (int i = h + 1; i < stack_top; i++) {
            above.push_back(stacks[src][i]);
        }
        // above[0] is just above target, above.back() is at top of stack

        // Strategy: scan from top, group non-important boxes together,
        // but isolate near-future boxes so they end up on top of dest stacks

        // Process from top of stack (end of above array) downward
        int pos = above.size() - 1; // current top position in above[]

        while (pos >= 0) {
            // Current top of the real stack
            int real_top_idx = stacks[src].size() - 1;
            int boxes_to_consider = real_top_idx - h; // number above target

            if (boxes_to_consider <= 0) break;

            // Look at the top portion and decide cut point
            // The boxes currently above target in the stack
            int cur_src = box_pos[target_k].first;
            int cur_h = box_pos[target_k].second;
            int cur_top = stacks[cur_src].size();

            if (cur_h == cur_top - 1) break; // target is on top

            // Find the lowest "important" box in the current above-target block
            // Important = within lookahead_window of target_k
            int best_split = -1; // index in stack to start the move from

            // Simple strategy: move everything at once to the best destination
            // But check if the bottom of the block is an important box - if so, isolate it

            int first_above = cur_h + 1;
            int bottom_box = stacks[cur_src][first_above];

            if (bottom_box > target_k && bottom_box < target_k + lookahead_window && cur_top - first_above > 1) {
                // The box just above target is near-future - move everything above IT first
                // so it ends up on top, then move it individually to a good spot
                int second_above = first_above + 1;
                int block_box = stacks[cur_src][second_above]; // start of upper block
                int dest = best_dest_for_block(target_k, stacks[cur_src], second_above, cur_top - second_above, cur_src);
                if (dest >= 0) {
                    do_move(block_box, dest);
                }
                // Now bottom_box is on top, move it to a good destination
                dest = best_dest_for_single(bottom_box, target_k, cur_src);
                if (dest >= 0) {
                    do_move(bottom_box, dest);
                }
            } else {
                // Check if there's an important box somewhere in the middle
                bool found_important_in_middle = false;
                for (int i = first_above; i < cur_top; i++) {
                    int bv = stacks[cur_src][i];
                    if (bv > target_k && bv < target_k + lookahead_window / 2 && i < cur_top - 1) {
                        // Important box not at top - move stuff above it first
                        int block_start_box = stacks[cur_src][i + 1];
                        int dest = best_dest_for_block(target_k, stacks[cur_src], i + 1, cur_top - i - 1, cur_src);
                        if (dest >= 0) {
                            do_move(block_start_box, dest);
                            found_important_in_middle = true;
                            break;
                        }
                    }
                }

                if (!found_important_in_middle) {
                    // No special considerations - move everything above target at once
                    int block_start_box = stacks[cur_src][first_above];
                    int dest = best_dest_for_block(target_k, stacks[cur_src], first_above, cur_top - first_above, cur_src);
                    if (dest >= 0) {
                        do_move(block_start_box, dest);
                    }
                    break;
                }
            }

            // Recheck position
            pos = stacks[box_pos[target_k].first].size() - 1 - box_pos[target_k].second - 1;
        }

        // Now target should be on top
        do_carry_out(target_k);
    }

    int best_dest_for_single(int box_val, int target_k, int src_stack) {
        double best_score = 1e18;
        int best_d = -1;
        for (int d = 0; d < M; d++) {
            if (d == src_stack) continue;
            double score = 0.0;
            const auto& dst = stacks[d];

            // Prefer shorter stacks
            score += dst.size() * 0.3;

            // If this box is a near-future target, prefer empty or very short stacks
            if (box_val >= target_k && box_val < target_k + 10) {
                if (dst.empty()) {
                    score -= 20.0;
                }
                // Penalize putting on top of other near-future targets
                if (!dst.empty()) {
                    int top = dst.back();
                    if (top >= target_k && top < target_k + 10 && top < box_val) {
                        score += 30.0; // bad - covering something needed sooner
                    }
                }
            }

            // Penalty for covering near-future targets
            if (!dst.empty()) {
                int top = dst.back();
                if (top >= target_k && top < target_k + 15) {
                    score += 20.0 * (15 - (top - target_k)) / 15.0;
                }
            }

            if (score < best_score) {
                best_score = score;
                best_d = d;
            }
        }
        return best_d;
    }

    // Main solve with multi-move approach
    long long solve_multi_move(int lookahead_window) {
        reset_state();

        while (next_target < N) {
            process_target_multi_move(next_target, lookahead_window);
            do_cascades();
        }

        return energy;
    }

    // Simple single-move greedy for comparison
    long long solve_single_move_greedy() {
        reset_state();

        while (next_target < N) {
            int target_k = next_target;
            int src = box_pos[target_k].first;
            int h = box_pos[target_k].second;

            if (h == (int)stacks[src].size() - 1) {
                do_carry_out(target_k);
            } else {
                int first_above = stacks[src][h + 1];
                int dest = best_dest_for_block(target_k, stacks[src], h + 1, stacks[src].size() - h - 1, src);
                if (dest >= 0) {
                    do_move(first_above, dest);
                }
                do_carry_out(target_k);
            }
            do_cascades();
        }

        return energy;
    }

    // Parameterized multi-move with tunable parameters for SA
    struct Params {
        int lookahead_window;
        double empty_stack_bonus;
        double height_penalty;
        double cover_future_penalty;
        double near_future_isolate_threshold;
        int split_depth; // how deep to look for splitting opportunities
    };

    long long solve_parameterized(const Params& p) {
        reset_state();

        while (next_target < N) {
            int target_k = next_target;
            int src = box_pos[target_k].first;
            int h = box_pos[target_k].second;

            if (h == (int)stacks[src].size() - 1) {
                do_carry_out(target_k);
                do_cascades();
                continue;
            }

            int cur_top = stacks[src].size();
            int num_above = cur_top - h - 1;

            // Multi-move logic with parameterized decisions
            bool did_split = false;

            if (num_above > 1 && p.split_depth > 0) {
                // Look for near-future boxes in the block above
                for (int depth = 0; depth < std::min(p.split_depth, num_above - 1); depth++) {
                    int check_idx = h + 1 + depth; // from bottom of block upward
                    int bv = stacks[src][check_idx];

                    if (bv > target_k && bv < target_k + p.lookahead_window) {
                        // This near-future box is buried - expose it
                        if (check_idx < (int)stacks[src].size() - 1) {
                            // Move everything above it
                            int move_start = stacks[src][check_idx + 1];
                            int move_count = stacks[src].size() - check_idx - 1;

                            // Find best dest for this upper block
                            int best_d = -1;
                            double best_s = 1e18;
                            for (int d = 0; d < M; d++) {
                                if (d == src) continue;
                                double s = stacks[d].size() * p.height_penalty;
                                if (stacks[d].empty()) s -= p.empty_stack_bonus;
                                if (!stacks[d].empty()) {
                                    int top = stacks[d].back();
                                    if (top >= target_k && top < target_k + p.lookahead_window) {
                                        s += p.cover_future_penalty * (p.lookahead_window - (top - target_k));
                                    }
                                }
                                if (s < best_s) { best_s = s; best_d = d; }
                            }

                            if (best_d >= 0 && move_count > 0) {
                                do_move(move_start, best_d);
                                // Now bv might be on top or closer to top
                                // Also move bv itself to a good spot
                                if (stacks[src].back() == bv && depth > 0) {
                                    int dest_for_bv = -1;
                                    double best_s2 = 1e18;
                                    for (int d = 0; d < M; d++) {
                                        if (d == src) continue;
                                        double s = stacks[d].size() * 0.3;
                                        if (stacks[d].empty()) s -= 15.0;
                                        if (!stacks[d].empty()) {
                                            int top = stacks[d].back();
                                            if (top >= target_k && top < bv) {
                                                s += 25.0;
                                            }
                                        }
                                        if (s < best_s2) { best_s2 = s; dest_for_bv = d; }
                                    }
                                    if (dest_for_bv >= 0) {
                                        do_move(bv, dest_for_bv);
                                    }
                                }
                                did_split = true;
                                break;
                            }
                        }
                    }
                }
            }

            // After splitting (or not), move remaining above target
            src = box_pos[target_k].first;
            h = box_pos[target_k].second;
            if (h < (int)stacks[src].size() - 1) {
                int first_above = stacks[src][h + 1];
                int move_count = stacks[src].size() - h - 1;

                int best_d = -1;
                double best_s = 1e18;
                for (int d = 0; d < M; d++) {
                    if (d == src) continue;
                    double s = stacks[d].size() * p.height_penalty;
                    if (stacks[d].empty()) s -= p.empty_stack_bonus;
                    if (!stacks[d].empty()) {
                        int top = stacks[d].back();
                        if (top >= target_k && top < target_k + p.lookahead_window) {
                            s += p.cover_future_penalty * (p.lookahead_window - (top - target_k));
                        }
                    }
                    // Bonus if block contains boxes that complement destination
                    if (s < best_s) { best_s = s; best_d = d; }
                }

                if (best_d >= 0) {
                    do_move(first_above, best_d);
                }
            }

            do_carry_out(target_k);
            do_cascades();
        }

        return energy;
    }

    // SA over parameters
    void solve_with_sa() {
        // Try a few parameter settings, pick best, then refine with SA
        Params best_params;
        best_params.lookahead_window = 10;
        best_params.empty_stack_bonus = 8.0;
        best_params.height_penalty = 0.5;
        best_params.cover_future_penalty = 5.0;
        best_params.near_future_isolate_threshold = 5.0;
        best_params.split_depth = 3;

        long long best_energy_val = solve_parameterized(best_params);
        std::vector<std::pair<int,int>> best_ops = ops;

        // Try different parameter configurations
        std::vector<Params> configs = {
