const double TIME_LIMIT = 1.95;

struct Solver {
    int N, M;
    std::vector<std::vector<int>> initial_stacks; // 0-indexed box values

    // Simulation state
    std::vector<std::vector<int>> stacks;
    std::vector<std::pair<int,int>> box_pos; // box_val -> (stack_idx, height_idx)
    long long energy;
    std::vector<std::pair<int,int>> ops; // (box_val+1, dest_stack+1 or 0)
