        Params best_params;
        best_params.lookahead_window = 10;
        best_params.empty_stack_bonus = 8.0;
        best_params.height_penalty = 0.5;
        best_params.cover_future_penalty = 5.0;
        best_params.near_future_isolate_threshold = 5.0;
        best_params.split_depth = 3;

        long long best_energy_val = solve_parameterized(best_params);
        std::vector<std::pair<int,int>> best_ops = ops;

        // Try different parameter configurations
        std::vector<Params> configs = {
            {15, 10.0, 0.4, 6.0, 5.0, 4},
            {8, 6.0, 0.6, 4.0, 5.0, 2},
            {20, 12.0, 0.3, 8.0, 5.0, 5},
            {5, 5.0, 0.8, 3.0, 5.0, 1},
            {12, 7.0, 0.5, 5.0, 5.0, 3},
            {25, 15.0, 0.2, 10.0, 5.0, 6},
            {10, 5.0, 1.0, 4.0, 5.0, 2},
            {8, 12.0, 0.3, 7.0, 5.0, 4},
        };

        for (auto& cfg : configs) {
            if (elapsed_seconds() > 0.3) break;
