            int which = RGen.an_int(0, 5);
            switch (which) {
                case 0:
                    new_params.lookahead_window = std::max(3, std::min(40, current_params.lookahead_window + RGen.an_int(-3, 3)));
                    break;
                case 1:
                    new_params.empty_stack_bonus = std::max(0.0, current_params.empty_stack_bonus + RGen.a_double(-3.0, 3.0));
