                    new_params.lookahead_window = std::max(3, std::min(40, current_params.lookahead_window + RGen.an_int(-2, 2)));
                    new_params.cover_future_penalty = std::max(0.0, current_params.cover_future_penalty + RGen.a_double(-1.0, 1.0));
                    new_params.split_depth = std::max(0, std::min(10, current_params.split_depth + RGen.an_int(-1, 1)));
