struct State {
    std::vector<int> stacks[M_CONST];
    int box_stack[N_CONST]; // box -> stack
    int box_height[N_CONST]; // box -> position in stack
    long long energy;
    int next_target;

    void init(const int initial[M_CONST][H_CONST]) {
        energy = 0;
        next_target = 0;
        for (int i = 0; i < M_CONST; i++) {
            stacks[i].clear();
            stacks[i].reserve(N_CONST);
            for (int j = 0; j < H_CONST; j++) {
                int bv = initial[i][j];
                stacks[i].push_back(bv);
                box_stack[bv] = i;
                box_height[bv] = j;
            }
        }
    }

    void move_block(int box_val, int dest) {
        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = stacks[src].size() - h;
        int old_dest_h = stacks[dest].size();

        for (int i = h; i < (int)stacks[src].size(); i++) {
            int bv = stacks[src][i];
            box_stack[bv] = dest;
            box_height[bv] = old_dest_h + (i - h);
            stacks[dest].push_back(bv);
        }
        stacks[src].resize(h);
        energy += (num_moved + 1);
    }

    void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stacks[src].pop_back();
        next_target++;
    }

    bool target_on_top() {
        int bv = next_target;
        int src = box_stack[bv];
        return (!stacks[src].empty() && stacks[src].back() == bv);
    }

    void do_cascades() {
        while (next_target < N_CONST && target_on_top()) {
            carry_out();
        }
    }
