                int first_above = state.stacks[src][h + 1];
                int pd = plan[target_k];
                if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                if (recorded_ops) recorded_ops->push_back({first_above, pd});
                state.move_block(first_above, pd);
            }

            if (recorded_ops) recorded_ops->push_back({target_k, -1}); // carry out
            state.carry_out();
        }

