    }

    // Generate initial greedy plan
    void generate_greedy_plan(std::vector<int>& plan, std::vector<bool>& split_flags,
                              std::vector<int>& split_dests, int lookahead) {
        plan.assign(N_CONST, 0);
        split_flags.assign(N_CONST, false);
        split_dests.assign(N_CONST, 0);

        state.init(initial);

        while (state.next_target < N_CONST) {
            state.do_cascades();
            if (state.next_target >= N_CONST) break;

            int target_k = state.next_target;
            int src = state.box_stack[target_k];
            int h = state.box_height[target_k];

            if (h == (int)state.stacks[src].size() - 1) {
                plan[target_k] = src;
                state.carry_out();
                continue;
            }

            int num_above = state.stacks[src].size() - h - 1;

            // Check for split opportunity
