    void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stacks[src].pop_back();
        next_target++;
    }

    bool target_on_top() {
        int bv = next_target;
        int src = box_stack[bv];
        return (!stacks[src].empty() && stacks[src].back() == bv);
    }

    void do_cascades() {
        while (next_target < N_CONST && target_on_top()) {
            carry_out();
        }
    }
};

// A "decision" for processing one target: list of (box_to_move, destination) pairs
// before the final carry-out
struct TargetDecision {
    // We store destination choices for each sub-move needed.
    // For simplicity, we'll represent it as: the sequence of moves needed.
    // But since this varies, let's use a different representation:
    // For each target, store just the "primary destination" and a "split flag"
    int primary_dest; // where to move the main block above target
    int split_dest;   // if splitting, where to move the exposed near-future box
    bool do_split;    // whether to split
    int split_box;    // which near-future box to isolate (-1 if none)
};

struct Solver {
    int initial[M_CONST][H_CONST];
    State state;

    void read_input() {
        for (int i = 0; i < M_CONST; i++)
            for (int j = 0; j < H_CONST; j++)
                std::cin >> initial[i][j];
        // Convert to 0-indexed
        for (int i = 0; i < M_CONST; i++)
            for (int j = 0; j < H_CONST; j++)
                initial[i][j]--;
    }

    // Greedy scoring for choosing a destination
    int greedy_best_dest(int target_k, int src, int lookahead) {
        int best_d = -1;
        double best_s = 1e18;
        for (int d = 0; d < M_CONST; d++) {
            if (d == src) continue;
            double s = 0;
            const auto& dst = state.stacks[d];
            s += dst.size() * 0.5;
            if (dst.empty()) {
                s -= 8.0;
            } else {
                // Penalty for covering near-future boxes
                for (int i = (int)dst.size() - 1; i >= std::max(0, (int)dst.size() - 5); i--) {
                    int bv = dst[i];
                    if (bv > target_k && bv < target_k + lookahead) {
                        double urgency = (double)(lookahead - (bv - target_k)) / lookahead;
                        s += 8.0 * urgency;
                        if (i == (int)dst.size() - 1) s += 12.0 * urgency; // top penalty extra
                    }
                }
            }
            if (s < best_s) { best_s = s; best_d = d; }
        }
        return best_d;
    }

    // Process one target using a decision plan
    void process_target(int target_k, int dest_override) {
        int src = state.box_stack[target_k];
        int h = state.box_height[target_k];

        if (h == (int)state.stacks[src].size() - 1) {
            // Already on top
            state.carry_out();
            return;
        }

        // Move everything above target to dest_override
        int first_above = state.stacks[src][h + 1];
        int actual_dest = dest_override;
        if (actual_dest == src || actual_dest < 0 || actual_dest >= M_CONST) {
            actual_dest = (src + 1) % M_CONST;
        }
        state.move_block(first_above, actual_dest);
        state.carry_out();
    }

    // Simulate with a plan (one dest per target)
    long long simulate_plan(const std::vector<int>& plan) {
        state.init(initial);
        for (int k = 0; k < N_CONST; k++) {
            if (state.next_target > k) continue; // already carried out via cascade
            if (state.next_target < k) break; // something wrong

            // Wait - cascades might have advanced next_target past k
            // We need to handle this differently
            while (state.next_target < N_CONST) {
                state.do_cascades();
                if (state.next_target >= N_CONST) break;
                int target_k = state.next_target;
                process_target(target_k, plan[target_k]);
                state.do_cascades();
            }
            break; // outer loop is just to start the inner loop
        }
        // Make sure all are processed
        while (state.next_target < N_CONST) {
            state.do_cascades();
            if (state.next_target >= N_CONST) break;
            int target_k = state.next_target;
            process_target(target_k, plan[target_k]);
        }
        return state.energy;
    }

    // Better simulate that uses multi-move splitting
    struct MoveRecord {
        int box_val; // 0-indexed
        int dest;    // 0-indexed
    };

    long long simulate_with_splits(const std::vector<int>& plan, const std::vector<bool>& split_flags,
                                    const std::vector<int>& split_dests, bool record_ops,
                                    std::vector<MoveRecord>* recorded_ops = nullptr) {
        state.init(initial);

        if (recorded_ops) recorded_ops->clear();

        while (state.next_target < N_CONST) {
            state.do_cascades();
            if (state.next_target >= N_CONST) break;

            int target_k = state.next_target;
            int src = state.box_stack[target_k];
            int h = state.box_height[target_k];

            if (h == (int)state.stacks[src].size() - 1) {
                if (recorded_ops) recorded_ops->push_back({target_k, -1}); // carry out
                state.carry_out();
                continue;
            }

            int num_above = state.stacks[src].size() - h - 1;

            // Check if we should split
            if (split_flags[target_k] && num_above > 1) {
                // Find first near-future box in the block (from bottom up)
                int split_box_idx = -1;
                for (int i = h + 1; i < (int)state.stacks[src].size() - 1; i++) {
                    int bv = state.stacks[src][i];
                    if (bv > target_k && bv < target_k + 15) {
                        split_box_idx = i;
                        break;
                    }
                }

                if (split_box_idx >= 0 && split_box_idx < (int)state.stacks[src].size() - 1) {
                    // Move everything above split_box to split_dest
                    int upper_block_start = state.stacks[src][split_box_idx + 1];
                    int sd = split_dests[target_k];
                    if (sd == src || sd < 0 || sd >= M_CONST) sd = (src + 1) % M_CONST;

                    if (recorded_ops) recorded_ops->push_back({upper_block_start, sd});
                    state.move_block(upper_block_start, sd);

                    // Now move the split_box to a good place
                    int split_bv = state.stacks[src].back();
                    if (split_bv != target_k && state.stacks[src].size() - 1 > (size_t)h) {
                        // Move remaining above target (might be just split_bv or more)
                        int first_above_now = state.stacks[src][h + 1];
                        int pd = plan[target_k];
                        if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                        if (recorded_ops) recorded_ops->push_back({first_above_now, pd});
                        state.move_block(first_above_now, pd);
                    }
                } else {
                    // No suitable split point, just move all
                    int first_above = state.stacks[src][h + 1];
                    int pd = plan[target_k];
                    if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                    if (recorded_ops) recorded_ops->push_back({first_above, pd});
                    state.move_block(first_above, pd);
                }
            } else {
                // No split, move all above target to plan dest
                int first_above = state.stacks[src][h + 1];
                int pd = plan[target_k];
                if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                if (recorded_ops) recorded_ops->push_back({first_above, pd});
                state.move_block(first_above, pd);
            }

            if (recorded_ops) recorded_ops->push_back({target_k, -1}); // carry out
            state.carry_out();
        }

        return state.energy;
    }

    // Generate initial greedy plan
    void generate_greedy_plan(std::vector<int>& plan, std::vector<bool>& split_flags,
                              std::vector<int>& split_dests, int lookahead) {
        plan.assign(N_CONST, 0);
        split_flags.assign(N_CONST, false);
        split_dests.assign(N_CONST, 0);

        state.init(initial);

        while (state.next_target < N_CONST) {
            state.do_cascades();
            if (state.next_target >= N_CONST) break;

            int target_k = state.next_target;
            int src = state.box_stack[target_k];
            int h = state.box_height[target_k];

            if (h == (int)state.stacks[src].size() - 1) {
                plan[target_k] = src;
                state.carry_out();
                continue;
            }

            int num_above = state.stacks[src].size() - h - 1;

            // Check for split opportunity
            if (num_above > 1) {
                int split_box_idx = -1;
                for (int i = h + 1; i < (int)state.stacks[src].size() - 1; i++) {
                    int bv = state.stacks[src][i];
                    if (bv > target_k && bv < target_k + 15) {
                        split_box_idx = i;
                        break;
                    }
                }

                if (split_box_idx >= 0 && split_box_idx < (int)state.stacks[src].size() - 1) {
                    split_flags[target_k] = true;
                    // Choose dest for upper block
                    int upper_start = state.stacks[src][split_box_idx + 1];
                    int sd = greedy_best_dest(target_k, src, lookahead);
                    split_dests[target_k] = sd;

                    // Move upper block
                    if (sd >= 0 && sd != src) {
                        state.move_block(upper_start, sd);
                    }

                    // Move remaining above target
                    if (state.box_height[target_k] < (int)state.stacks[src].size() - 1) {
                        int first_above = state.stacks[src][state.box_height[target_k] + 1];
                        int pd = greedy_best_dest(target_k, src, lookahead);
                        plan[target_k] = pd;
                        if (pd >= 0 && pd != src) {
                            state.move_block(first_above, pd);
                        }
                    } else {
                        plan[target_k] = src;
                    }
                } else {
                    split_flags[target_k] = false;
                    int pd = greedy_best_dest(target_k, src, lookahead);
                    plan[target_k] = pd;
                    int first_above = state.stacks[src][h + 1];
                    if (pd >= 0 && pd != src) {
                        state.move_block(first_above, pd);
                    }
                }
            } else {
                split_flags[target_k] = false;
                int pd = greedy_best_dest(target_k, src, lookahead);
                plan[target_k] = pd;
                int first_above = state.stacks[src][h + 1];
                if (pd >= 0 && pd != src) {
                    state.move_block(first_above, pd);
                }
            }

            state.carry_out();
        }
    }

    void solve() {
        // Phase 1: Generate initial greedy plan with different lookaheads
        std::vector<int> best_plan;
        std::vector<bool> best_split_flags;
        std::vector<int> best_split_dests;
        long long best_energy = 1e18;

        for (int la : {8, 10, 12, 15, 20}) {
            if (elapsed_seconds() > 0.15) break;
            std::vector<int> plan;
            std::vector<bool> sf;
            std::vector<int> sd;
            generate_greedy_plan(plan, sf, sd, la);
            long long e = simulate_with_splits(plan, sf, sd, false);
            if (e < best_energy) {
                best_energy = e;
                best_plan = plan;
                best_split_flags = sf;
                best_split_dests = sd;
            }
        }

        // Phase 2: SA over plan decisions
        std::vector<int> current_plan = best_plan;
        std::vector<bool> current_sf = best_split_flags;
        std::vector<int> current_sd = best_split_dests;
        long long current_energy = best_energy;

        double T_init = 30.0;
        double T_final = 0.05;
        double sa_start = elapsed_seconds();
        double sa_budget = TIME_LIMIT - sa_start - 0.05;

        while (elapsed_seconds() < TIME_LIMIT - 0.05) {
            double progress = (elapsed_seconds() - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            std::vector<int> new_plan = current_plan;
            std::vector<bool> new_sf = current_sf;
            std::vector<int> new_sd = current_sd;

            // Perturbation
            int op = RGen.an_int(0, 99);

            if (op < 40) {
                // Change one primary dest
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 70) {
                // Change a block of primary dests
                int idx = RGen.an_int(0, N_CONST - 1);
                int len = RGen.an_int(1, std::min(15, N_CONST - idx));
                for (int i = 0; i < len; i++) {
                    new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
                }
            } else if (op < 85) {
                // Toggle split flag
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sf[idx] = !new_sf[idx];
                if (new_sf[idx]) {
                    new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                }
            } else {
                // Change split dest
                int idx = RGen.an_int(0, N_CONST - 1);
                if (new_sf[idx]) {
                    new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                } else {
                    new_sf[idx] = true;
                    new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                }
            }

            long long new_e = simulate_with_splits(new_plan, new_sf, new_sd, false);

            if (new_e < current_energy) {
                current_energy = new_e;
                current_plan = new_plan;
                current_sf = new_sf;
                current_sd = new_sd;
                if (new_e < best_energy) {
                    best_energy = new_e;
                    best_plan = new_plan;
                    best_split_flags = new_sf;
                    best_split_dests = new_sd;
                }
            } else {
                double delta = new_e - current_energy;
                if (T > 1e-9 && RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
                    current_energy = new_e;
                    current_plan = new_plan;
                    current_sf = new_sf;
                    current_sd = new_sd;
                }
            }
        }

        // Output the best solution
        output_solution(best_plan, best_split_flags, best_split_dests);
    }

    void output_solution(const std::vector<int>& plan, const std::vector<bool>& split_flags,
                         const std::vector<int>& split_dests) {
        state.init(initial);

        while (state.next_target < N_CONST) {
            state.do_cascades();
            if (state.next_target >= N_CONST) break;

            int target_k = state.next_target;
            int src = state.box_stack[target_k];
            int h = state.box_height[target_k];

            if (h == (int)state.stacks[src].size() - 1) {
                std::cout << (target_k + 1) << " 0\n";
                state.carry_out();
                continue;
            }

            int num_above = state.stacks[src].size() - h - 1;

            if (split_flags[target_k] && num_above > 1) {
                int split_box_idx = -1;
                for (int i = h + 1; i < (int)state.stacks[src].size() - 1; i++) {
                    int bv = state.stacks[src][i];
                    if (bv > target_k && bv < target_k + 15) {
                        split_box_idx = i;
                        break;
                    }
                }

                if (split_box_idx >= 0 && split_box_idx < (int)state.stacks[src].size() - 1) {
                    int upper_block_start = state.stacks[src][split_box_idx + 1];
                    int sd = split_dests[target_k];
                    if (sd == src || sd < 0 || sd >= M_CONST) sd = (src + 1) % M_CONST;
                    std::cout << (upper_block_start + 1) << " " << (sd + 1) << "\n";
                    state.move_block(upper_block_start, sd);

                    if (state.box_height[target_k] < (int)state.stacks[src].size() - 1) {
                        int first_above_now = state.stacks[src][state.box_height[target_k] + 1];
                        int pd = plan[target_k];
                        if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                        std::cout << (first_above_now + 1) << " " << (pd + 1) << "\n";
                        state.move_block(first_above_now, pd);
                    }
                } else {
                    int first_above = state.stacks[src][h + 1];
                    int pd = plan[target_k];
                    if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                    std::cout << (first_above + 1) << " " << (pd + 1) << "\n";
                    state.move_block(first_above, pd);
                }
            } else {
                int first_above = state.stacks[src][h + 1];
                int pd = plan[target_k];
                if (pd == src || pd < 0 || pd >= M_CONST) pd = (src + 1) % M_CONST;
                std::cout << (first_above + 1) << " " << (pd + 1) << "\n";
                state.move_block(first_above, pd);
            }

            std::cout << (target_k + 1) << " 0\n";
            state.carry_out();
        }
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    Solver solver;
    solver.read_input();
    solver.solve();

    return 0;
}
