# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <algorithm>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

const double TIME_LIMIT = 1.95;
const int N_CONST = 200;
const int M_CONST = 10;
const int H_CONST = 20;

struct State {
    std::vector<int> stacks[M_CONST];
    int box_stack[N_CONST];
    int box_height[N_CONST];
    long long energy;
    int next_target;

    void init(const int initial[M_CONST][H_CONST]) {
        energy = 0;
        next_target = 0;
        for (int i = 0; i < M_CONST; i++) {
            stacks[i].clear();
            stacks[i].reserve(N_CONST);
            for (int j = 0; j < H_CONST; j++) {
                int bv = initial[i][j];
                stacks[i].push_back(bv);
                box_stack[bv] = i;
                box_height[bv] = j;
            }
        }
    }

    void move_block(int box_val, int dest) {
        int src = box_stack[box_val];
        int h = box_height[box_val];
        int num_moved = (int)stacks[src].size() - h;
        int old_dest_h = (int)stacks[dest].size();

        for (int i = h; i < h + num_moved; i++) {
            int bv = stacks[src][i];
            box_stack[bv] = dest;
            box_height[bv] = old_dest_h + (i - h);
            stacks[dest].push_back(bv);
        }
        stacks[src].resize(h);
        energy += (num_moved + 1);
    }

    void carry_out() {
        int bv = next_target;
        int src = box_stack[bv];
        stacks[src].pop_back();
        next_target++;
    }

    bool target_on_top() const {
        if (next_target >= N_CONST) return false;
        int bv = next_target;
        int src = box_stack[bv];
        return (!stacks[src].empty() && stacks[src].back() == bv);
    }
};

struct Solver {
    int initial[M_CONST][H_CONST];

    void read_input() {
        for (int i = 0; i < M_CONST; i++)
            for (int j = 0; j < H_CONST; j++) {
                std::cin >> initial[i][j];
                initial[i][j]--;
            }
    }

    int greedy_best_dest(const State& st, int target_k, int src, int lookahead) {
        int best_d = -1;
        double best_s = 1e18;
        for (int d = 0; d < M_CONST; d++) {
            if (d == src) continue;
            double s = 0;
            const auto& dst = st.stacks[d];
            s += (double)dst.size() * 0.5;
            if (dst.empty()) {
                s -= 8.0;
            } else {
                for (int i = (int)dst.size() - 1; i >= std::max(0, (int)dst.size() - 5); i--) {
                    int bv = dst[i];
                    if (bv > target_k && bv < target_k + lookahead) {
                        double urgency = (double)(lookahead - (bv - target_k)) / lookahead;
                        s += 8.0 * urgency;
                        if (i == (int)dst.size() - 1) s += 12.0 * urgency;
                    }
                }
            }
            if (s < best_s) { best_s = s; best_d = d; }
        }
        return best_d;
    }

    // Simulate full solution with given plan. Returns energy.
    // plan[k] = dest for boxes above target k (0-indexed dest)
    // split_flags[k] = whether to attempt split at target k
    // split_dests[k] = dest for upper portion when splitting
    long long simulate(const std::vector<int>& plan, const std::vector<bool>& split_flags,
                       const std::vector<int>& split_dests) {
        State st;
        st.init(initial);

        while (st.next_target < N_CONST) {
            // Cascades
            while (st.target_on_top()) st.carry_out();
            if (st.next_target >= N_CONST) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int stack_size = (int)st.stacks[src].size();

            if (h == stack_size - 1) {
                st.carry_out();
                continue;
            }

            int num_above = stack_size - h - 1;

            if (split_flags[target_k] && num_above > 1) {
