                    memcpy(best_plan, plan, sizeof(plan));
                    memcpy(best_sf, sf, sizeof(sf));
                    memcpy(best_sd, sd, sizeof(sd));
                    best_split_range = sr;
                }
            }
            if (elapsed_seconds() > 0.15) break;
        }

        memcpy(cur_plan, best_plan, sizeof(best_plan));
        memcpy(cur_sf, best_sf, sizeof(best_sf));
        memcpy(cur_sd, best_sd, sizeof(best_sd));
        long long cur_energy = best_energy;

        // SA phase
        double T_init = 20.0;
        double T_final = 0.01;
        double sa_start = elapsed_seconds();
        double sa_end = TIME_LIMIT - 0.05;
        double sa_budget = sa_end - sa_start;

        int new_plan[N_CONST];
        bool new_sf[N_CONST];
        int new_sd[N_CONST];

        while (true) {
            double now = elapsed_seconds();
            if (now >= sa_end) break;
            double progress = (now - sa_start) / sa_budget;
            double T = T_init * std::pow(T_final / T_init, progress);

            memcpy(new_plan, cur_plan, sizeof(cur_plan));
            memcpy(new_sf, cur_sf, sizeof(cur_sf));
            memcpy(new_sd, cur_sd, sizeof(cur_sd));

            int op = RGen.an_int(0, 99);
