                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 60) {
                int idx = RGen.an_int(0, N_CONST - 1);
                int len = RGen.an_int(2, std::min(14, N_CONST - idx));
                for (int i = 0; i < len; i++)
                    new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 75) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sf[idx] = !new_sf[idx];
                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 88) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = true;
            } else {
                // Swap two plan entries
                int i1 = RGen.an_int(0, N_CONST - 1);
                int i2 = RGen.an_int(0, N_CONST - 1);
                std::swap(new_plan[i1], new_plan[i2]);
            }

            long long new_e = simulate(new_plan, new_sf, new_sd, best_split_range);

            if (new_e < cur_energy) {
                cur_energy = new_e;
                memcpy(cur_plan, new_plan, sizeof(new_plan));
                memcpy(cur_sf, new_sf, sizeof(new_sf));
                memcpy(cur_sd, new_sd, sizeof(new_sd));
                if (new_e < best_energy) {
                    best_energy = new_e;
                    memcpy(best_plan, new_plan, sizeof(new_plan));
                    memcpy(best_sf, new_sf, sizeof(new_sf));
                    memcpy(best_sd, new_sd, sizeof(new_sd));
                }
            } else {
                double delta = (double)(new_e - cur_energy);
                if (RGen.a_double() < std::exp(-delta / T)) {
                    cur_energy = new_e;
                    memcpy(cur_plan, new_plan, sizeof(new_plan));
                    memcpy(cur_sf, new_sf, sizeof(new_sf));
                    memcpy(cur_sd, new_sd, sizeof(new_sd));
                }
            }
        }

        output(best_plan, best_sf, best_sd, best_split_range);
