    void generate_greedy_plan(std::vector<int>& plan, std::vector<bool>& split_flags,
                              std::vector<int>& split_dests, int lookahead, int split_range) {
        plan.assign(N_CONST, 0);
        split_flags.assign(N_CONST, false);
        split_dests.assign(N_CONST, 0);

        State st;
        st.init(initial);

        while (st.next_target < N_CONST) {
            while (st.target_on_top()) st.carry_out();
            if (st.next_target >= N_CONST) break;

            int target_k = st.next_target;
            int src = st.box_stack[target_k];
            int h = st.box_height[target_k];
            int src_sz = (int)st.stacks[src].size();

            if (h == src_sz - 1) {
                plan[target_k] = src;
                st.carry_out();
                continue;
            }

            int num_above = src_sz - h - 1;

            if (num_above > 1) {
                int split_box_idx = -1;
                for (int i = h + 1; i < src_sz - 1; i++) {
                    int bv = st.stacks[src][i];
                    if (bv > target_k && bv < target_k + split_range) {
                        split_box_idx = i;
                        break;
                    }
                }

                if (split_box_idx >= 0) {
                    split_flags[target_k] = true;
                    int upper_start_box = st.stacks[src][split_box_idx + 1];
                    int sd = greedy_best_dest(st, target_k, src, lookahead);
                    if (sd < 0 || sd == src) sd = (src + 1) % M_CONST;
                    split_dests[target_k] = sd;
                    st.move_block(upper_start_box, sd);

                    src = st.box_stack[target_k];
                    h = st.box_height[target_k];
                    if (h < (int)st.stacks[src].size() - 1) {
                        int pd = greedy_best_dest(st, target_k, src, lookahead);
                        if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
                        plan[target_k] = pd;
                        int first_above = st.stacks[src][h + 1];
                        st.move_block(first_above, pd);
                    } else {
                        plan[target_k] = src;
                    }
                } else {
                    int pd = greedy_best_dest(st, target_k, src, lookahead);
                    if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
                    plan[target_k] = pd;
                    int first_above = st.stacks[src][h + 1];
                    st.move_block(first_above, pd);
                }
            } else {
                int pd = greedy_best_dest(st, target_k, src, lookahead);
                if (pd < 0 || pd == src) pd = (src + 1) % M_CONST;
                plan[target_k] = pd;
                int first_above = st.stacks[src][h + 1];
                st.move_block(first_above, pd);
            }

            st.carry_out();
        }
    }

    void solve() {
        std::vector<int> best_plan;
        std::vector<bool> best_sf;
        std::vector<int> best_sd;
        long long best_energy = (long long)1e18;
        int best_split_range = 15;

        // Try greedy with different configs
        for (int sr : {10, 15, 20, 25}) {
            for (int la : {8, 10, 12, 15, 20, 25}) {
                if (elapsed_seconds() > 0.15) goto done_greedy;
                std::vector<int> plan;
                std::vector<bool> sf;
                std::vector<int> sd;
                generate_greedy_plan(plan, sf, sd, la, sr);
                long long e = simulate(plan, sf, sd, sr);
                if (e < best_energy) {
                    best_energy = e;
                    best_plan = plan;
                    best_sf = sf;
                    best_sd = sd;
                    best_split_range = sr;
                }
            }
        }
        done_greedy:

        std::vector<int> cur_plan = best_plan;
        std::vector<bool> cur_sf = best_sf;
        std::vector<int> cur_sd = best_sd;
        long long cur_energy = best_energy;

        // SA phase
        double T_init = 20.0;
        double T_final = 0.01;
        double sa_start = elapsed_seconds();
        double sa_end = TIME_LIMIT - 0.05;
        double sa_budget = sa_end - sa_start;

        while (elapsed_seconds() < sa_end) {
            double progress = (elapsed_seconds() - sa_start) / sa_budget;
            if (progress > 1.0) break;
            double T = T_init * std::pow(T_final / T_init, progress);

            std::vector<int> new_plan = cur_plan;
            std::vector<bool> new_sf = cur_sf;
            std::vector<int> new_sd = cur_sd;

            int op = RGen.an_int(0, 99);
            if (op < 35) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 60) {
                int idx = RGen.an_int(0, N_CONST - 1);
                int len = RGen.an_int(2, std::min(14, N_CONST - idx));
                for (int i = 0; i < len; i++)
                    new_plan[idx + i] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 75) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sf[idx] = !new_sf[idx];
                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
            } else if (op < 88) {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_sd[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = true;
            } else {
                int idx = RGen.an_int(0, N_CONST - 1);
                new_plan[idx] = RGen.an_int(0, M_CONST - 1);
                new_sf[idx] = (RGen.an_int(0, 1) == 1);
                if (new_sf[idx]) new_sd[idx] = RGen.an_int(0, M_CONST - 1);
            }

            long long new_e = simulate(new_plan, new_sf, new_sd, best_split_range);

            if (new_e < cur_energy) {
                cur_energy = new_e;
                cur_plan = new_plan;
                cur_sf = new_sf;
                cur_sd = new_sd;
                if (new_e < best_energy) {
                    best_energy = new_e;
                    best_plan = new_plan;
                    best_sf = new_sf;
                    best_sd = new_sd;
                }
            } else {
                double delta = (double)(new_e - cur_energy);
                if (RGen.a_double(0.0, 1.0) < std::exp(-delta / T)) {
                    cur_energy = new_e;
                    cur_plan = new_plan;
                    cur_sf = new_sf;
                    cur_sd = new_sd;
                }
            }
        }

        output(best_plan, best_sf, best_sd, best_split_range);
    }
};

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;

    Solver solver;
    solver.read_input();
    solver.solve();

    return 0;
}
